  height: 44px !important;
  margin: -44px 0 0 0 !important;
  background: transparent !important;
  border: none !important;
  padding: 0 !important;
  cursor: pointer !important;
  position: relative !important;
  z-index: 5 !important;
  opacity: 0 !important;
  font-size: 0 !important;
}
.xt-action-5::after,.xt-action-6::after,
.xt-action-7::after,.xt-action-8::after { content: "" !important; }

/* ══════════════════════
   FOOTER
══════════════════════ */
.xt-footer {
  font-size: 10.5px !important;
  color: #9cc4d8 !important;
  text-align: center !important;
  padding: 9px 0 6px !important;
  border-top: 1px dashed #c2e0f4 !important;
  margin-top: 4px !important;
  letter-spacing: 1px !important;
  font-style: normal !important;
}

/* ══════════════════════
   入场动画
══════════════════════ */
@keyframes xtUp {
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: translateY(0); }
}
.xt-content > * { animation: xtUp 0.26s ease-out both; }
.xt-content > *:nth-child(1)  { animation-delay: 0.00s; }
.xt-content > *:nth-child(2)  { animation-delay: 0.04s; }
.xt-content > *:nth-child(3)  { animation-delay: 0.08s; }
.xt-content > *:nth-child(4)  { animation-delay: 0.12s; }
.xt-content > *:nth-child(5)  { animation-delay: 0.16s; }
.xt-content > *:nth-child(6)  { animation-delay: 0.20s; }
.xt-content > *:nth-child(7)  { animation-delay: 0.24s; }
.xt-content > *:nth-child(8)  { animation-delay: 0.28s; }
.xt-content > *:nth-child(9)  { animation-delay: 0.32s; }
.xt-content > *:nth-child(10) { animation-delay: 0.36s; }
.xt-content > *:nth-child(11) { animation-delay: 0.40s; }
.xt-content > *:nth-child(12) { animation-delay: 0.44s; }
.xt-content > *:nth-child(13) { animation-delay: 0.48s; }
.xt-content > *:nth-child(14) { animation-delay: 0.52s; }
.xt-content > *:nth-child(15) { animation-delay: 0.56s; }
/* ══════════════════════
   颜文字 footer
══════════════════════ */
.xt-text-footerKao {
  display: block !important;
  text-align: center !important;
  font-size: 13px !important;
  color: #9cc4d8 !important;
  padding: 9px 0 6px !important;
