charBubbleCSS:
:root{
  /* ===== 背景色 ===== */
  --transfer-card-bg:           #FA9D3B;   /* 未操作：深橙 */
  --transfer-card-bg-received:  #FCE2BC;   /* 已接受/已退回：浅橙 */
  --transfer-card-bg-expired:   #E6C7A5;   /* 已过期：灰色 */
  --transfer-icon-default:
    url('https://i.postimg.cc/j5CqLH5J/wu-biao-ti38-20260205143013.png');
  --transfer-icon-received:
    url('https://nos.netease.com/ysf/032ae26e2e69a232d3bb904047b34e38.png');
  --transfer-icon-returned:
    url('https://nos.netease.com/ysf/0b5a28d77f1934fdcc6750fd8f9897c6.png');
  --transfer-icon-expired:
      url('https://nos.netease.com/ysf/dfbb30c0b7383f9209c03597b101adfe.png');
  /* ===== 备注文字（未操作时显示） ===== */
  --transfer-me-remark:    "你发起了一笔转账";
  --transfer-them-remark:  "请收款";
  /* ===== 底部"微信转账" ===== */
  --transfer-status-text:  "微信转账";
  /* ===== 📐 位置 / 字距微调 ===== */
  --amount-top:            14px;     /* 金额垂直位置 */
  --amount-left:           68px;     /* 金额水平位置 */
  --amount-font-size:      20px;     /* 金额字号 */
  --amount-letter-spacing: -1.2px;   /* 金额字距（越负越紧凑） */
  --remark-top:            40px;     /* 备注垂直位置 */
  --remark-left:           68px;     /* 备注水平位置 */
  --expire-display:        block;    /* 过期提示文字：block=显示 / none=隐藏 */
}

.msg-transfer-card{
  position: relative !important;
  width: 264px !important;
  height: 96px !important;
  margin: 0 auto !important;
  padding: 0 !important;
  border: none !important;
  border-radius: 4px !important;
  background: var(--transfer-card-bg) !important;
  overflow: hidden !important;
  box-shadow: none !important;
  transition: background-color .25s ease !important;
}
.msg-transfer-card .msg-transfer-icon svg,
.msg-transfer-card .msg-transfer-icon img,
.msg-transfer-card .msg-transfer-label,
.msg-transfer-card .msg-transfer-subtitle,
.msg-transfer-card .msg-transfer-divider,
.msg-transfer-card .msg-transfer-footer,
.msg-transfer-card .msg-transfer-status-text,
.msg-transfer-card .msg-transfer-chevron,
.msg-transfer-card .msg-transfer-check,
.msg-transfer-card .msg-transfer-dot,
.msg-transfer-card .msg-transfer-header > svg,
.msg-transfer-card .msg-transfer-content > svg{
  display: none !important;
}
.msg-transfer-card .msg-transfer-content{
  position: relative !important;
  width: 100% !important;
  height: 100% !important;
}
.msg-transfer-card .msg-transfer-header{
  position: static !important;
  display: block !important;
}
.msg-transfer-card .msg-transfer-icon{
  position: absolute !important;
  top: 12px !important;
  left: 12px !important;
  width: 44px !important;
  height: 44px !important;
  display: block !important;

  background-image: var(--transfer-icon-default) !important;
  background-size: contain !important;
  background-repeat: no-repeat !important;
  background-position: center !important;
  background-color: transparent !important;

  font-size: 0 !important;
  color: transparent !important;
  z-index: 3 !important;
  opacity: 1 !important;
  visibility: visible !important;
}
.msg-transfer-card .msg-transfer-amount-section{
  position: absolute !important;
  top: var(--amount-top) !important;
  left: var(--amount-left) !important;
  right: 12px !important;
  display: block !important;
  font-size: 0 !important;
  line-height: 1 !important;
  z-index: 5 !important;
}

.msg-transfer-card .msg-transfer-amount{
  display: block !important;
  margin: 0 !important;
  padding: 0 !important;
  font-size: var(--amount-font-size) !important;
  font-weight: 700 !important;
  line-height: 1 !important;
  color: #ffffff !important;
  -webkit-text-fill-color: #ffffff !important;
  letter-spacing: var(--amount-letter-spacing) !important;
  white-space: nowrap !important;
  overflow: visible !important;
  text-align: left !important;
  font-variant-numeric: tabular-nums !important;
}

.msg-transfer-card .msg-transfer-amount span,
.msg-transfer-card .msg-transfer-amount *{
  display: inline !important;
  writing-mode: horizontal-tb !important;
  font-size: var(--amount-font-size) !important;
  font-weight: 700 !important;
  color: #ffffff !important;
  -webkit-text-fill-color: #ffffff !important;
  white-space: nowrap !important;
  letter-spacing: var(--amount-letter-spacing) !important;
  word-spacing: -3px !important;
}
.msg-transfer-card .msg-transfer-content::after{
  position: absolute !important;
  top: var(--remark-top) !important;
  left: var(--remark-left) !important;
  right: 12px !important;

  font-size: 12px !important;
  font-weight: 400 !important;
  line-height: 1.2 !important;

  color: rgba(255,255,255,.92) !important;
  -webkit-text-fill-color: rgba(255,255,255,.92) !important;

  white-space: nowrap !important;
  overflow: hidden !important;
  text-overflow: ellipsis !important;
  z-index: 10 !important;
}
.msg-transfer-card::before{
  content: var(--transfer-status-text) !important;
  position: absolute !important;
  left: 12px !important;
  bottom: 8px !important;

  font-size: 11px !important;
  font-weight: 600 !important;
  line-height: 1 !important;

  color: rgba(255,255,255,.82) !important;
  -webkit-text-fill-color: rgba(255,255,255,.82) !important;
  z-index: 5 !important;
}

.msg-transfer-card .msg-transfer-expiry{
  display: var(--expire-display) !important;
  position: absolute !important;
  right: 12px !important;
  bottom: 8px !important;
  left: auto !important;
  top: auto !important;

  margin: 0 !important;
  padding: 0 !important;

  font-size: 10px !important;
  font-weight: 400 !important;
  line-height: 1 !important;
  text-align: right !important;

  color: rgba(255,255,255,.75) !important;
  -webkit-text-fill-color: rgba(255,255,255,.75) !important;
  background: transparent !important;

  z-index: 6 !important;
  opacity: 1 !important;
  visibility: visible !important;
}
.msg-me .msg-transfer-card,
.msg-them .msg-transfer-card,
.bubble-me-custom .msg-transfer-card,
.bubble-them-custom .msg-transfer-card{
  background: var(--transfer-card-bg) !important;
}

.msg-me .msg-transfer-card .msg-transfer-icon,
.msg-them .msg-transfer-card .msg-transfer-icon,
.bubble-me-custom .msg-transfer-card .msg-transfer-icon,
.bubble-them-custom .msg-transfer-card .msg-transfer-icon{
  background-image: var(--transfer-icon-default) !important;
}

.msg-me .msg-transfer-card .msg-transfer-content::after,
.bubble-me-custom .msg-transfer-card .msg-transfer-content::after{
  content: var(--transfer-me-remark) !important;
}

.msg-them .msg-transfer-card .msg-transfer-content::after,
.bubble-them-custom .msg-transfer-card .msg-transfer-content::after{
  content: var(--transfer-them-remark) !important;
}
.msg-me .msg-transfer-card.msg-transfer-success,
.msg-them .msg-transfer-card.msg-transfer-success,
.bubble-me-custom .msg-transfer-card.msg-transfer-success,
.bubble-them-custom .msg-transfer-card.msg-transfer-success{
  background: var(--transfer-card-bg-received) !important;
  background-color: var(--transfer-card-bg-received) !important;
}

.msg-transfer-card.msg-transfer-success .msg-transfer-icon{
  background-image: var(--transfer-icon-received) !important;
}

.msg-me .msg-transfer-card.msg-transfer-success .msg-transfer-content::after,
.bubble-me-custom .msg-transfer-card.msg-transfer-success .msg-transfer-content::after{
  content: "已收款" !important;
}

.msg-them .msg-transfer-card.msg-transfer-success .msg-transfer-content::after,
.bubble-them-custom .msg-transfer-card.msg-transfer-success .msg-transfer-content::after{
  content: "已被接受" !important;
}
.msg-me .msg-transfer-card.msg-transfer-rejected,
.msg-them .msg-transfer-card.msg-transfer-rejected,
.bubble-me-custom .msg-transfer-card.msg-transfer-rejected,
.bubble-them-custom .msg-transfer-card.msg-transfer-rejected{
  background: var(--transfer-card-bg-received) !important;
  background-color: var(--transfer-card-bg-received) !important;
}

.msg-transfer-card.msg-transfer-rejected .msg-transfer-icon{
  background-image: var(--transfer-icon-returned) !important;
}

.msg-me .msg-transfer-card.msg-transfer-rejected .msg-transfer-content::after,
.bubble-me-custom .msg-transfer-card.msg-transfer-rejected .msg-transfer-content::after{
  content: "已被退还" !important;
}

.msg-them .msg-transfer-card.msg-transfer-rejected .msg-transfer-content::after,
.bubble-them-custom .msg-transfer-card.msg-transfer-rejected .msg-transfer-content::after{
  content: "已退还" !important;
}
.msg-me .msg-transfer-card.msg-transfer-expired-card,
.msg-them .msg-transfer-card.msg-transfer-expired-card,
.bubble-me-custom .msg-transfer-card.msg-transfer-expired-card,
.bubble-them-custom .msg-transfer-card.msg-transfer-expired-card{
  background: var(--transfer-card-bg-expired) !important;
  background-color: var(--transfer-card-bg-expired) !important;
}

.msg-transfer-card.msg-transfer-expired-card .msg-transfer-icon{
  background-image: var(--transfer-icon-expired) !important;
}

.msg-me .msg-transfer-card.msg-transfer-expired-card .msg-transfer-content::after,
.bubble-me-custom .msg-transfer-card.msg-transfer-expired-card .msg-transfer-content::after{
  content: "已过期" !important;
}

.msg-them .msg-transfer-card.msg-transfer-expired-card .msg-transfer-content::after,
.bubble-them-custom .msg-transfer-card.msg-transfer-expired-card .msg-transfer-content::after{
  content: "已过期" !important;
}

/* 已过期时不再显示"22小时后过期"提示 */
.msg-transfer-card.msg-transfer-expired-card .msg-transfer-expiry{
  display: none !important;
}


