/* ===== 通话美化 ===== */
:root {
  --call-avatar-image:
    url('https://nos.netease.com/ysf/b162f75b7995445115f2da8ee4af6b9c.png');

  /* ===== 颜色 ===== */
  --call-card-bg-me:     #95ec69;
  --call-card-bg-them:   #ffffff;
  --call-text-main:      #1a1a1a;
  --call-text-me-cancel:   "已取消";
  --call-text-them-reject: "对方已取消";
  --call-text-connected:   "通话时长 ";
}

.msg-videocall-card,
.msg-videocall-card.missed,
.msg-videocall-card.connected,
.msg-videocall-card.cancelled,
.msg-videocall-card.rejected {
  width: fit-content !important;
  min-width: 0 !important;              /* ✅ 关键：取消内联 200px */
  max-width: 240px !important;
  padding: 8px 12px !important;
  border-radius: 4px !important;
  box-shadow: none !important;
  border: none !important;
  display: flex !important;
  align-items: center !important;
  gap: 8px !important;
  position: relative !important;
  cursor: default !important;
  background: var(--call-card-bg-them) !important;
}
.bubble-me-custom .msg-videocall-card,
.msg-me .msg-videocall-card {
  background: var(--call-card-bg-me) !important;
}
.bubble-me-custom .msg-videocall-card::after,
.msg-me .msg-videocall-card::after {
  content: "" !important;
  position: absolute !important;
  top: 14px !important;
  right: -4px !important;
  width: 8px !important;
  height: 8px !important;
  background: var(--call-card-bg-me) !important;
  border-radius: 1.5px !important;
  transform: rotate(45deg) !important;
  z-index: -1 !important;
  display: block !important;
  visibility: visible !important;
  opacity: 1 !important;
}

.bubble-them-custom .msg-videocall-card::before,
.msg-them .msg-videocall-card::before {
  content: "" !important;
  position: absolute !important;
  top: 14px !important;
  left: -4px !important;
  width: 8px !important;
  height: 8px !important;
  background: var(--call-card-bg-them) !important;
  border-radius: 1.5px !important;
  transform: rotate(45deg) !important;
  z-index: -1 !important;
  display: block !important;
  visibility: visible !important;
  opacity: 1 !important;
}

.msg-videocall-card > div:first-child {
  width: 24px !important;
  height: 24px !important;
  min-width: 24px !important;
  min-height: 24px !important;
  border-radius: 0 !important;
  background: var(--call-avatar-image) center / contain no-repeat !important;
  background-color: transparent !important;
  background-image: var(--call-avatar-image) !important;
  box-shadow: none !important;
  border: none !important;
  flex-shrink: 0 !important;
  font-size: 0 !important;
  color: transparent !important;
  overflow: visible !important;
  display: block !important;
}
.msg-videocall-card > div:first-child svg,
.msg-videocall-card > div:first-child svg * {
  display: none !important;
  visibility: hidden !important;
  opacity: 0 !important;
  width: 0 !important;
  height: 0 !important;
  fill: transparent !important;
  stroke: transparent !important;
  filter: none !important;
}
.msg-videocall-card > div:nth-child(2) {
  display: flex !important;
  flex-direction: row !important;
  align-items: center !important;
  justify-content: flex-start !important;
  max-width: none !important;
  gap: 4px !important;
}
.msg-videocall-card > div:nth-child(2) > div:first-child {
  font-weight: 500 !important;
  color: var(--call-text-main) !important;
  -webkit-text-fill-color: var(--call-text-main) !important;
  letter-spacing: 0 !important;
  white-space: nowrap !important;
  overflow: hidden !important;
  margin: 0 !important;
  font-size: 0 !important;
}
.msg-videocall-card > div:nth-child(2) > div:first-child::before {
  font-size: 14px !important;
  font-weight: 500 !important;
  color: var(--call-text-main) !important;
  -webkit-text-fill-color: var(--call-text-main) !important;
  content: "通话已结束" !important;
}
.bubble-me-custom .msg-videocall-card.missed > div:nth-child(2) > div:first-child::before,
.msg-me .msg-videocall-card.missed > div:nth-child(2) > div:first-child::before {
  content: var(--call-text-me-cancel) !important;
}
.bubble-them-custom .msg-videocall-card.missed > div:nth-child(2) > div:first-child::before,
.msg-them .msg-videocall-card.missed > div:nth-child(2) > div:first-child::before {
  content: var(--call-text-them-reject) !important;
}
.msg-videocall-card.connected > div:nth-child(2) > div:first-child::before {
  content: var(--call-text-connected) !important;
}
.msg-videocall-card > div:nth-child(2) > div:nth-child(2),
.msg-videocall-card > div:nth-child(2) > div:nth-child(2) * {
  display: none !important;
  visibility: hidden !important;
  opacity: 0 !important;
  width: 0 !important;
  height: 0 !important;
  font-size: 0 !important;
}
.msg-videocall-card.connected > div:nth-child(2) > div:nth-child(2) {
  display: inline-flex !important;
  visibility: visible !important;
  opacity: 1 !important;
  width: auto !important;
  height: auto !important;
  font-size: 14px !important;
  font-weight: 500 !important;
  color: var(--call-text-main) !important;
  -webkit-text-fill-color: var(--call-text-main) !important;
  margin: 0 !important;
  padding: 0 !important;
  background: transparent !important;
  gap: 0 !important;
  letter-spacing: 0 !important;
}
.msg-videocall-card.connected > div:nth-child(2) > div:nth-child(2) * {
  display: inline !important;
  visibility: visible !important;
  opacity: 1 !important;
  width: auto !important;
  height: auto !important;
  font-size: 14px !important;
  color: var(--call-text-main) !important;
  -webkit-text-fill-color: var(--call-text-main) !important;
}
.msg-videocall-card > div:nth-child(3),
.msg-videocall-card > div:nth-child(3) * {
  display: none !important;
  visibility: hidden !important;
  opacity: 0 !important;
  width: 0 !important;
  height: 0 !important;
}


:root {
  --voice-bubble-me-bg: #95ec69;       /* 我方气泡绿 */
  --voice-bubble-them-bg: #ffffff;     /* 对方气泡白 */
  --voice-duration-color: #000;
  --voice-transcription-bg: #ffffff;
  --voice-transcription-color: #1a1a1a;
}

/* ============ 外层气泡透明 ============ */
.bubble-me-custom:has(.voice-msg),
.bubble-them-custom:has(.voice-msg) {
  background: transparent !important;
  padding: 0 !important;
  border: none !important;
  box-shadow: none !important;
  overflow: visible !important;
}
.bubble-me-custom:has(.voice-msg)::after,
.bubble-them-custom:has(.voice-msg)::before {
  display: none !important;
}
/* ============ ▶ 播放按钮 ============ */
.voice-play-btn {
  position: relative !important;
  width: 24px !important;
  height: 24px !important;
  padding: 0 !important;
  flex-shrink: 0 !important;
  border: none !important;
  border-radius: 0 !important;
  background-image: url("https://i.postimg.cc/kXymFms9/wu-biao-ti161-20260515061153.png") !important;
  background-size: contain !important;
  background-repeat: no-repeat !important;
  background-position: center !important;
  background-color: transparent !important;
  margin-top: -1px !important;
  order: 2 !important;                    /* ✅ 我方默认：▶ 在右边 */
  right: 4px !important;
  left: auto !important;
  transform: scaleX(-1) !important;       /* ✅ 我方箭头朝左 */
}

/* ✅ 对方：▶ 在左边，箭头朝右（默认方向） */
.msg-them .voice-play-btn,
.voice-msg-them .voice-play-btn {
  order: 0 !important;
  left: 4px !important;
  right: auto !important;
  transform: none !important;
}

/* 隐藏原生 SVG */
.voice-play-btn svg,
.voice-play-btn svg *,
.voice-play-btn > svg,
.voice-play-btn > svg > * {
  display: none !important;
  visibility: hidden !important;
  opacity: 0 !important;
  width: 0 !important;
  height: 0 !important;
  fill: transparent !important;
  stroke: transparent !important;
  color: transparent !important;
}

/* ============ 波形透明 ============ */
.voice-waveform {
  opacity: 0 !important;
  margin: 0 !important;
  height: 12px !important;
  flex: 1 !important;
  pointer-events: none !important;
}

/* ============ 「查看语音内容」按钮 → 透明可点 ============ */
.voice-transcription-toggle {
  position: absolute !important;
  inset: 0 !important;
  width: 100% !important;
  height: 100% !important;
  padding: 0 !important;
  margin: 0 !important;
  background: transparent !important;
  border: none !important;
  cursor: pointer !important;
  z-index: 5 !important;
  font-size: 0 !important;
  color: transparent !important;
  opacity: 1 !important;
  white-space: nowrap !important;
  overflow: hidden !important;
}
/* ============ 转写文字气泡 ============ */
.voice-transcription {
  position: relative !important;
  display: block !important;
  margin-top: 6px !important;
  background: var(--voice-transcription-bg) !important;
  color: var(--voice-transcription-color) !important;
  border-radius: 4px !important;
  padding: 12px 14px !important;
  font-size: 15px !important;
  line-height: 1.5 !important;
  width: fit-content !important;
  max-width: 260px !important;
  min-width: 180px !important;
  white-space: normal !important;
  word-break: break-word !important;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.06) !important;
  box-sizing: border-box !important;
}
.voice-transcription,
.voice-transcription * {
  color: var(--voice-transcription-color) !important;
}
.voice-msg-me .voice-transcription {
  margin-left: auto !important;
  margin-right: 0 !important;
}

.msg-translation-detached-them { align-self: flex-start !important; }
.msg-translation-detached-me   { align-self: flex-end !important; }

/* ============ 隐藏下载按钮 ============ */
.voice-download-btn,
.voice-download,
.voice-download-toggle,
[class*="voice-download"],
[class*="download-btn"] {
  display: none !important;
  visibility: hidden !important;
  opacity: 0 !important;
  width: 0 !important;
  height: 0 !important;
  pointer-events: none !important;
}
.bubble-deco-me:has(.voice-msg),
.bubble-deco-them:has(.voice-msg) {
  background: transparent !important;
  padding: 0 !important;
  border: none !important;
  box-shadow: none !important;
  overflow: visible !important;
}
（msg-bg-prem-me） 
.msg-bubble-container:has(.voice-msg),
.msg-bg-prem-me:has(.voice-msg),
.msg-bg-prem-them:has(.voice-msg) {
  background: transparent !important;
  background-image: none !important;
  box-shadow: none !important;
}

.voice-msg {
  overflow: visible !important;
}
.voice-controls-row {
  width: 105px !important;
  min-width: 105px !important;
  max-width: 105px !important;
  border-radius: 4px !important;
  min-height: 38px !important;
  position: relative !important;
  box-sizing: border-box !important;
}
.voice-msg-me .voice-controls-row {
  background: var(--voice-bubble-me-bg) !important;
  padding: 8px 8px 8px 0 !important;   /* 我方右侧放▶：右侧留空间更自然 */
}
.voice-msg-them .voice-controls-row {
  background: var(--voice-bubble-them-bg) !important;
  padding: 8px 0 8px 8px !important;   /* 对方左侧放▶ */
}

/* 5) 小尖角：分别加（现在不会被 overflow:hidden 裁掉了） */
.voice-msg-me .voice-controls-row::after {
  content: "" !important;
  position: absolute !important;
  top: 14px !important;
  right: -4px !important;
  width: 8px !important;
  height: 8px !important;
  background: var(--voice-bubble-me-bg) !important;
  border-radius: 1.5px !important;
  transform: rotate(45deg) !important;
  z-index: -1 !important;
  display: block !important;
}
.voice-msg-them .voice-controls-row::after {
  content: "" !important;
  position: absolute !important;
  top: 14px !important;
  left: -4px !important;
  right: auto !important;
  width: 8px !important;
  height: 8px !important;
  background: var(--voice-bubble-them-bg) !important;
  border-radius: 1.5px !important;
  transform: rotate(45deg) !important;
  z-index: -1 !important;
  display: block !important;
}

/* 6) ▶ 按钮：用真实类区分我方/对方 */
.voice-play-btn { background-color: transparent !important; }

/* 我方 ▶ 在右 + 翻转 */
.voice-msg-me .voice-play-btn {
  order: 2 !important;
  margin-left: auto !important;
  transform: scaleX(-1) !important;
}
/* 对方 ▶ 在左 */
.voice-msg-them .voice-play-btn {
  order: 0 !important;
  margin-right: auto !important;
  transform: none !important;
}

.voice-waveform { opacity: 0 !important; }
.voice-duration {
  display: inline-block !important;
  position: absolute !important;
  top: 50% !important;
  transform: translateY(-50%) !important;
  font-size: 12px !important;
  font-weight: 600 !important;
  color: var(--voice-duration-color) !important;
  -webkit-text-fill-color: var(--voice-duration-color) !important;
  white-space: nowrap !important;
  overflow: hidden !important;
  background: transparent !important;
}

.voice-msg-me .voice-duration {
  right: 30px !important;
  left: auto !important;
  width: 22px !important;
  text-indent: -12px !important;   /* 去掉 0: */
}

.voice-msg-them .voice-duration {
  left: 38px !important;
  right: auto !important;
  width: 27px !important;
  text-indent: -12px !important;   /* 去掉 0: */
}

/* 对方引号：保持原来 */
.voice-msg-them .voice-duration::after {
  content: '"' !important;
  position: absolute !important;
  right: 0px !important;
  top: 50% !important;
  transform: translateY(-50%) !important;
}
.voice-msg-me .voice-duration::after {
  content: '"' !important;
  position: absolute !important;
  right: -6px !important;      /* ✅ 0 → -3：引号向右移动 */
  top: 50% !important;
  transform: translateY(-50%) !important;
}
.voice-transcription-toggle {
  position: absolute !important;
  inset: 0 !important;
  width: 100% !important;
  height: 100% !important;
  background: transparent !important;
  border: none !important;
  cursor: pointer !important;
  z-index: 5 !important;
  color: transparent !important;
  font-size: 0 !important;
}
.voice-transcription-toggle svg,
.voice-transcription-toggle svg * {
  display: none !important;
}

.voice-transcription {
  display: block !important;
  background: var(--voice-transcription-bg) !important;
  color: var(--voice-transcription-color) !important;
  -webkit-text-fill-color: var(--voice-transcription-color) !important;
}
.voice-transcription,
.voice-transcription * {
  color: var(--voice-transcription-color) !important;
  -webkit-text-fill-color: var(--voice-transcription-color) !important;
  opacity: 1 !important;
  visibility: visible !important;
}

