/* ===== 微信礼物美化 ===== */

:root{
  --gift-card-bg-closed:  #0F4C9B;
  --gift-card-bg-opened:  #7A93BC;
  --gift-text-color-closed: #F5D78A;
  --gift-text-color-opened: #E0E0E0;
  --gift-bow-image:
    url('https://nos.netease.com/ysf/7b82fbc7c55b54b4a21ea22d5a539868.png');
  --bow-left: 8px;       /* 左右位置，数字越大越靠右 */
  --bow-top: 50%;         /* 上下位置，50% = 垂直居中 */
  --bow-offset-y: -65%;   /* 微调上下偏移 */
  --bow-size: 80px;       /* 蝴蝶结大小 */
  --gift-text-main:      "送你一份心意";
  --gift-text-opened:    "已收下";
  --gift-bottom-text:    "微信礼物";
}
@keyframes gift-sparkle-1{
  0%,100%{ opacity: 0; }
  50%{ opacity: 1; }
}
@keyframes gift-sparkle-2{
  0%,100%{ opacity: 0; }
  40%{ opacity: 0.8; }
  80%{ opacity: 0; }
}
@keyframes gift-sparkle-3{
  0%,100%{ opacity: 0; }
  30%{ opacity: 1; }
  70%{ opacity: 0.3; }
}
.gift-ig-container.msg-gift-card{
  position: relative !important;
  width: 240px !important;
  height: 120px !important;
  margin: 0 auto !important;
  padding: 0 !important;
  border: none !important;
  border-radius: 8px !important;
  overflow: hidden !important;
  box-shadow: 0 2px 6px rgba(0,0,0,.1) !important;
  cursor: pointer !important;
  background: var(--gift-card-bg-closed) !important;
}
.gift-ig-container .gift-ig-box{
  display: block !important;
  position: absolute !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  bottom: 0 !important;
  width: 100% !important;
  height: 100% !important;
  margin: 0 !important;
  padding: 0 !important;
  background: transparent !important;
  border: none !important;
  box-shadow: none !important;
  overflow: visible !important;
  opacity: 1 !important;
  pointer-events: auto !important;
  transform: none !important;
  animation: none !important;
}

.gift-ig-container .gift-ig-lid,
.gift-ig-container .gift-ig-lid-ribbon,
.gift-ig-container .gift-ig-body,
.gift-ig-container .gift-ig-ribbon-v,
.gift-ig-container .gift-ig-ribbon-h,
.gift-ig-container .gift-ig-preview > svg,
.gift-ig-container .gift-ig-preview-text > svg{
  display: none !important;
}
.gift-ig-container .gift-ig-tissue{
  display: block !important;
  position: absolute !important;
  top: 0 !important;
  left: 0 !important;
  width: 240px !important;
  height: 120px !important;
  /* 反向定位回到卡片左上角（因为它在 .gift-ig-body 里） */
  transform: none !important;
  margin: 0 !important;
  padding: 0 !important;
  background:
    radial-gradient(1px 1px at 20% 20%, #FFD700 50%, transparent 100%),
    radial-gradient(1.5px 1.5px at 75% 15%, #FFEC8B 50%, transparent 100%),
    radial-gradient(1px 1px at 40% 65%, #FFD700 50%, transparent 100%),
    radial-gradient(1.5px 1.5px at 85% 55%, #FFF8DC 50%, transparent 100%),
    radial-gradient(1px 1px at 15% 80%, #FFEC8B 50%, transparent 100%),
    radial-gradient(1.5px 1.5px at 60% 40%, #FFD700 50%, transparent 100%),
    radial-gradient(1px 1px at 90% 80%, #FFEC8B 50%, transparent 100%),
    radial-gradient(1px 1px at 50% 10%, #FFF8DC 50%, transparent 100%),
    radial-gradient(1.5px 1.5px at 30% 45%, #FFD700 50%, transparent 100%),
    radial-gradient(1px 1px at 70% 75%, #FFEC8B 50%, transparent 100%),
    radial-gradient(1px 1px at 10% 50%, #FFD700 50%, transparent 100%),
    radial-gradient(1.5px 1.5px at 95% 35%, #FFF8DC 50%, transparent 100%) !important;
  background-color: transparent !important;
  border: none !important;
  box-shadow: none !important;
  animation: gift-sparkle-1 2.5s ease-in-out infinite !important;
  z-index: 1 !important;
  pointer-events: none !important;
}

.gift-ig-container .gift-ig-tissue::before{
  content: "" !important;
  display: block !important;
  position: absolute !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  bottom: 0 !important;
  background:
    radial-gradient(1px 1px at 55% 25%, #FFD700 50%, transparent 100%),
    radial-gradient(1.5px 1.5px at 25% 55%, #FFEC8B 50%, transparent 100%),
    radial-gradient(1px 1px at 80% 70%, #FFF8DC 50%, transparent 100%),
    radial-gradient(1px 1px at 45% 85%, #FFD700 50%, transparent 100%),
    radial-gradient(1.5px 1.5px at 65% 10%, #FFEC8B 50%, transparent 100%),
    radial-gradient(1px 1px at 10% 35%, #FFD700 50%, transparent 100%),
    radial-gradient(1px 1px at 35% 95%, #FFF8DC 50%, transparent 100%),
    radial-gradient(1.5px 1.5px at 88% 45%, #FFEC8B 50%, transparent 100%) !important;
  animation: gift-sparkle-2 3s ease-in-out 0.8s infinite !important;
  pointer-events: none !important;
}

.gift-ig-container .gift-ig-tissue::after{
  content: "" !important;
  display: block !important;
  position: absolute !important;
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  bottom: 0 !important;

  background:
    radial-gradient(1.5px 1.5px at 33% 12%, #FFD700 50%, transparent 100%),
    radial-gradient(1px 1px at 72% 48%, #FFEC8B 50%, transparent 100%),
    radial-gradient(1px 1px at 18% 68%, #FFF8DC 50%, transparent 100%),
    radial-gradient(1.5px 1.5px at 58% 58%, #FFD700 50%, transparent 100%),
    radial-gradient(1px 1px at 42% 30%, #FFEC8B 50%, transparent 100%),
    radial-gradient(1px 1px at 82% 90%, #FFF8DC 50%, transparent 100%) !important;
  animation: gift-sparkle-3 2s ease-in-out 1.5s infinite !important;
  pointer-events: none !important;
}
.gift-ig-container .gift-ig-body{
  display: block !important;
  position: absolute !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  background: transparent !important;
  border: none !important;
  box-shadow: none !important;
  transform: none !important;
  animation: none !important;
}
.gift-ig-container .gift-ig-bow{
  display: block !important;
  position: absolute !important;
  top: 50% !important;
  left: 12px !important;
  right: auto !important;
  bottom: auto !important;
  transform: translateY(-55%) !important;

  width: 80px !important;
  height: 80px !important;
  margin: 0 !important;
  padding: 0 !important;

  background: var(--gift-bow-image) center / contain no-repeat !important;
  background-color: transparent !important;
  border: none !important;
  box-shadow: none !important;
  animation: none !important;
  z-index: 4 !important;
  opacity: 1 !important;
  visibility: visible !important;
}
.gift-ig-container .gift-ig-bow::before,
.gift-ig-container .gift-ig-bow::after{
  display: none !important;
  content: none !important;
}
.gift-ig-container .gift-ig-preview{
  display: block !important;
  position: absolute !important;
  top: 48px !important;
  left: 100px !important;
  right: 12px !important;

  width: auto !important;
  height: auto !important;
  margin: 0 !important;
  padding: 0 !important;

  background: transparent !important;
  border: none !important;
  box-shadow: none !important;
  transform: none !important;
  animation: none !important;

  z-index: 5 !important;
  pointer-events: none !important;
}

.gift-ig-container .gift-ig-preview-text{
  display: block !important;
  margin: 0 !important;
  padding: 0 !important;

  font-size: 12px !important;
  font-weight: 400 !important;
  line-height: 1.2 !important;

  color: rgba(255,255,255,.75) !important;
  -webkit-text-fill-color: rgba(255,255,255,.75) !important;

  white-space: nowrap !important;
  overflow: hidden !important;
  text-overflow: ellipsis !important;

  background: transparent !important;
}

.gift-ig-container .gift-ig-preview-text > span{
  display: inline !important;
  color: inherit !important;
  -webkit-text-fill-color: inherit !important;
  font-size: inherit !important;
}
.gift-ig-container .gift-ig-label{
  display: none !important;   /* 默认隐藏，opened 才出现 */
  position: absolute !important;
  top: 48px !important;
  left: 100px !important;
  margin: 0 !important;
  padding: 0 !important;
  font-size: 0 !important;
  color: transparent !important;
  -webkit-text-fill-color: transparent !important;
  z-index: 5 !important;
  pointer-events: none !important;
}
.gift-ig-container.msg-gift-card::before{
  content: var(--gift-text-main) !important;
  position: absolute !important;
  top: 24px !important;
  left: 100px !important;
  right: 12px !important;
  display: block !important;
  font-size: 15px !important;
  font-weight: 600 !important;
  line-height: 1.3 !important;
  color: var(--gift-text-color-closed) !important;
  -webkit-text-fill-color: var(--gift-text-color-closed) !important;
  letter-spacing: 0.5px !important;
  white-space: nowrap !important;
  overflow: hidden !important;
  text-overflow: ellipsis !important;

  z-index: 6 !important;
  pointer-events: none !important;
}
.gift-ig-container.msg-gift-card::after{
  content: var(--gift-bottom-text) !important;
  position: absolute !important;
  left: 0 !important;
  right: 0 !important;
  bottom: 0 !important;
  height: 26px !important;
  line-height: 26px !important;
  padding-left: 14px !important;
  font-size: 11px !important;
  font-weight: 500 !important;
  color: rgba(255,255,255,.7) !important;
  -webkit-text-fill-color: rgba(255,255,255,.7) !important;
  border-top: 1px solid rgba(255,255,255,.15) !important;
  background: transparent !important;
  z-index: 6 !important;
  pointer-events: none !important;
}
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-closed){
  background: var(--gift-card-bg-closed) !important;
}
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-closed)::before{
  color: var(--gift-text-color-closed) !important;
  -webkit-text-fill-color: var(--gift-text-color-closed) !important;
}
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-closed) .gift-ig-preview{
  display: none !important;
}
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-opened){
  background: var(--gift-card-bg-opened) !important;
}
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-opened)::before{
  color: var(--gift-text-color-opened) !important;
  -webkit-text-fill-color: var(--gift-text-color-opened) !important;
}
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-opened) .gift-ig-preview{
  display: block !important;
}
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-opened) .gift-ig-preview-text > span::before{
  content: var(--gift-text-opened) " · " !important;
