  -webkit-text-fill-color: rgba(255,255,255,.55) !important;
}
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-opened) .gift-ig-tissue{
  opacity: 0.3 !important;
  animation: none !important;
}
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-opened) .gift-ig-tissue::before,
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-opened) .gift-ig-tissue::after{
  animation: none !important;
  opacity: 0.3 !important;
}
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-opened)::after{
  color: rgba(255,255,255,.6) !important;
  -webkit-text-fill-color: rgba(255,255,255,.6) !important;
  border-top: 1px solid rgba(255,255,255,.12) !important;
}
.gift-ig-container .gift-ig-preview,
.gift-ig-container .gift-ig-preview *,
.gift-ig-container .gift-ig-preview-text,
.gift-ig-container .gift-ig-preview-text *,
.gift-ig-container .gift-ig-preview-text > span{
  background: transparent !important;
  background-color: transparent !important;
  background-image: none !important;
  border: none !important;
  border-radius: 0 !important;
  outline: none !important;
  box-shadow: none !important;
  padding: 0 !important;
}
.gift-ig-container .gift-ig-preview-text > span{
  display: inline !important;
  padding: 0 !important;
  margin: 0 !important;
}

/* --- 蝴蝶结用变量控制位置 --- */
.gift-ig-container .gift-ig-bow{
  left: var(--bow-left) !important;
  top: var(--bow-top) !important;
  transform: translateY(var(--bow-offset-y)) !important;
  width: var(--bow-size) !important;
  height: var(--bow-size) !important;
}
.gift-ig-container.msg-gift-card:has(.gift-ig-box.status-opened) .gift-ig-bow{
  opacity: 0.55 !important;
  filter: grayscale(30%) brightness(0.9) !important;
  transition: opacity 0.3s ease !important;
}



/* ===== 通话美化 ===== */
:root {
  --call-avatar-image:
    url('https://nos.netease.com/ysf/b162f75b7995445115f2da8ee4af6b9c.png');

  /* ===== 颜色 ===== */
  --call-card-bg-me:     #95ec69;
  --call-card-bg-them:   #ffffff;
  --call-text-main:      #1a1a1a;
  --call-text-me-cancel:   "已取消";
  --call-text-them-reject: "对方已取消";
  --call-text-connected:   "通话时长 ";
}

.msg-videocall-card,
.msg-videocall-card.missed,
.msg-videocall-card.connected,
.msg-videocall-card.cancelled,
.msg-videocall-card.rejected {
  width: fit-content !important;
  min-width: 0 !important;              /* ✅ 关键：取消内联 200px */
  max-width: 240px !important;
  padding: 8px 12px !important;
  border-radius: 4px !important;
  box-shadow: none !important;
  border: none !important;
  display: flex !important;
  align-items: center !important;
  gap: 8px !important;
  position: relative !important;
  cursor: default !important;
  background: var(--call-card-bg-them) !important;
}
.bubble-me-custom .msg-videocall-card,
.msg-me .msg-videocall-card {
  background: var(--call-card-bg-me) !important;
}
.bubble-me-custom .msg-videocall-card::after,
.msg-me .msg-videocall-card::after {
  content: "" !important;
  position: absolute !important;
  top: 14px !important;
